class Solution:
    def reverseOnlyLetters(self, s: str) -> str:
        arr = list(s)
        lo, hi = 0, len(arr) - 1
        while lo < hi:
            while lo < hi and not arr[lo].isalpha():
                lo += 1
            while lo < hi and not arr[hi].isalpha():
                hi -= 1
            if lo < hi:
                arr[lo], arr[hi] = arr[hi], arr[lo]
                lo += 1
                hi -= 1
        return ''.join(arr)

