var reverseOnlyLetters = function(s) {
    const arr = s.split('');
    let lo = 0, hi = arr.length - 1;
    while (lo < hi) {
        while (lo < hi && !/[a-zA-Z]/.test(arr[lo])) lo++;
        while (lo < hi && !/[a-zA-Z]/.test(arr[hi])) hi--;
        if (lo < hi) {
            [arr[lo], arr[hi]] = [arr[hi], arr[lo]];
            lo++;
            hi--;
        }
    }
    return arr.join('');
};
